import React, { useEffect, useState } from 'react';
import axios from 'axios';

const s = {
  page: { padding: 32, maxWidth: 900, margin: '0 auto' },
  title: { fontSize: 22, fontWeight: 700, color: '#1a3a5c', marginBottom: 24 },
  grid: { display: 'grid', gridTemplateColumns: 'repeat(3,1fr)', gap: 18, marginBottom: 32 },
  card: { background: '#fff', borderRadius: 14, padding: '24px 20px', boxShadow: '0 2px 12px rgba(0,0,0,0.07)', textAlign: 'center' },
  num: { fontSize: 36, fontWeight: 800, marginBottom: 4 },
  label: { fontSize: 12, color: '#888', fontWeight: 600, textTransform: 'uppercase', letterSpacing: 1 },
  sectionTitle: { fontSize: 17, fontWeight: 700, color: '#1a3a5c', marginBottom: 14 },
  table: { width: '100%', borderCollapse: 'collapse', background: '#fff', borderRadius: 12, overflow: 'hidden', boxShadow: '0 2px 12px rgba(0,0,0,0.07)' },
  th: { background: '#1a3a5c', color: '#fff', padding: '12px 16px', textAlign: 'left', fontSize: 13 },
  td: { padding: '12px 16px', borderBottom: '1px solid #f5f5f5', fontSize: 14 },
};

const months = ['', 'Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];

export default function Reports() {
  const [summary, setSummary] = useState(null);
  const [monthly, setMonthly] = useState([]);

  useEffect(() => {
    axios.get('/api/report/summary').then(r => setSummary(r.data));
    axios.get('/api/report/monthly').then(r => setMonthly(r.data));
  }, []);

  return (
    <div style={s.page}>
      <div style={s.title}>📊 Reports & Analytics</div>

      <div style={s.grid}>
        <div style={s.card}><div style={{ ...s.num, color: '#2980b9' }}>{summary?.total ?? '—'}</div><div style={s.label}>Total Applications</div></div>
        <div style={s.card}><div style={{ ...s.num, color: '#27ae60' }}>{summary?.approved ?? '—'}</div><div style={s.label}>Approved</div></div>
        <div style={s.card}><div style={{ ...s.num, color: '#e74c3c' }}>{summary?.rejected ?? '—'}</div><div style={s.label}>Rejected</div></div>
        <div style={s.card}><div style={{ ...s.num, color: '#f39c12' }}>{summary?.pending ?? '—'}</div><div style={s.label}>Pending</div></div>
        <div style={s.card}><div style={{ ...s.num, color: '#95a5a6' }}>{summary?.expired ?? '—'}</div><div style={s.label}>Expired</div></div>
        <div style={s.card}><div style={{ ...s.num, color: '#8e44ad' }}>{summary?.students ?? '—'}</div><div style={s.label}>Students</div></div>
      </div>

      <div style={{ marginBottom: 28 }}>
        <div style={s.sectionTitle}>Pass Type Breakdown</div>
        <table style={s.table}>
          <thead><tr><th style={s.th}>Pass Type</th><th style={s.th}>Count</th></tr></thead>
          <tbody>
            {(summary?.byType || []).map(t => (
              <tr key={t._id}><td style={s.td}>{t._id || 'N/A'}</td><td style={s.td}><strong>{t.count}</strong></td></tr>
            ))}
            {(!summary?.byType?.length) && <tr><td colSpan={2} style={{ ...s.td, textAlign: 'center', color: '#aaa' }}>No data</td></tr>}
          </tbody>
        </table>
      </div>

      <div>
        <div style={s.sectionTitle}>Monthly Applications</div>
        <table style={s.table}>
          <thead><tr><th style={s.th}>Month</th><th style={s.th}>Year</th><th style={s.th}>Applications</th></tr></thead>
          <tbody>
            {monthly.map((m, i) => (
              <tr key={i}><td style={s.td}>{months[m._id.month]}</td><td style={s.td}>{m._id.year}</td><td style={s.td}><strong>{m.count}</strong></td></tr>
            ))}
            {!monthly.length && <tr><td colSpan={3} style={{ ...s.td, textAlign: 'center', color: '#aaa' }}>No data yet</td></tr>}
          </tbody>
        </table>
      </div>
    </div>
  );
}
